item.description:
 &lt;p&gt;作者: &lt;a href=&#34;http://paranimage.com/author/admin/&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34; title=&#34;由帕兰发布&#34;&gt;帕兰&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;1-PHP可阅读随机字符串&#34;&gt;&lt;a href=&#34;#1-PHP可阅读随机字符串&#34; class=&#34;headerlink&#34; title=&#34;1. PHP可阅读随机字符串&#34;&gt;&lt;/a&gt;1. PHP可阅读随机字符串&lt;/h3&gt;&lt;p&gt;此代码将创建一个可阅读的字符串，使其更接近词典中的单词，实用且具有密码验证功能。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/**************
*@length - length of random string (must be a multiple of 2)
**************/
function readable_random_string($length = 6){
    $conso=array(&amp;quot;b&amp;quot;,&amp;quot;c&amp;quot;,&amp;quot;d&amp;quot;,&amp;quot;f&amp;quot;,&amp;quot;g&amp;quot;,&amp;quot;h&amp;quot;,&amp;quot;j&amp;quot;,&amp;quot;k&amp;quot;,&amp;quot;l&amp;quot;,
    &amp;quot;m&amp;quot;,&amp;quot;n&amp;quot;,&amp;quot;p&amp;quot;,&amp;quot;r&amp;quot;,&amp;quot;s&amp;quot;,&amp;quot;t&amp;quot;,&amp;quot;v&amp;quot;,&amp;quot;w&amp;quot;,&amp;quot;x&amp;quot;,&amp;quot;y&amp;quot;,&amp;quot;z&amp;quot;);
    $vocal=array(&amp;quot;a&amp;quot;,&amp;quot;e&amp;quot;,&amp;quot;i&amp;quot;,&amp;quot;o&amp;quot;,&amp;quot;u&amp;quot;);
    $password=&amp;quot;&amp;quot;;
    srand ((double)microtime()*1000000);
    $max = $length/2;
    for($i=1; $i&amp;lt;=$max; $i++)
    {
    $password.=$conso[rand(0,19)];
    $password.=$vocal[rand(0,4)];
    }
    return $password;
}&lt;/code&gt;&lt;/pre&gt;&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;h3 id=&#34;2-PHP生成一个随机字符串&#34;&gt;&lt;a href=&#34;#2-PHP生成一个随机字符串&#34; class=&#34;headerlink&#34; title=&#34;2. PHP生成一个随机字符串&#34;&gt;&lt;/a&gt;2. PHP生成一个随机字符串&lt;/h3&gt;&lt;p&gt;如果不需要可阅读的字符串，使用此函数替代，即可创建一个随机字符串，作为用户的随机密码等。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/*************
*@l - length of random string
*/
function generate_rand($l){
  $c= &amp;quot;ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789&amp;quot;;
  srand((double)microtime()*1000000);
  for($i=0; $i&amp;lt;$l; $i++) {
      $rand.= $c[rand()%strlen($c)];
  }
  return $rand;
 }&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;3-PHP编码电子邮件地址&#34;&gt;&lt;a href=&#34;#3-PHP编码电子邮件地址&#34; class=&#34;headerlink&#34; title=&#34;3. PHP编码电子邮件地址&#34;&gt;&lt;/a&gt;3. PHP编码电子邮件地址&lt;/h3&gt;&lt;p&gt;使用此代码，可以将任何电子邮件地址编码为 HTML 字符实体，以防止被垃圾邮件程序收集。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function encode_email($email=&amp;apos;info@domain.com&amp;apos;, $linkText=&amp;apos;Contact Us&amp;apos;, $attrs =&amp;apos;class=&amp;quot;emailencoder&amp;quot;&amp;apos; )
{
    // remplazar aroba y puntos
    $email = str_replace(&amp;apos;@&amp;apos;, &amp;apos;&amp;amp;#64;&amp;apos;, $email);
    $email = str_replace(&amp;apos;.&amp;apos;, &amp;apos;&amp;amp;#46;&amp;apos;, $email);
    $email = str_split($email, 5);  

    $linkText = str_replace(&amp;apos;@&amp;apos;, &amp;apos;&amp;amp;#64;&amp;apos;, $linkText);
    $linkText = str_replace(&amp;apos;.&amp;apos;, &amp;apos;&amp;amp;#46;&amp;apos;, $linkText);
    $linkText = str_split($linkText, 5);  

    $part1 = &amp;apos;&amp;lt;a href=&amp;quot;ma&amp;apos;;
    $part2 = &amp;apos;ilto&amp;amp;#58;&amp;apos;;
    $part3 = &amp;apos;&amp;quot; &amp;apos;. $attrs .&amp;apos; &amp;gt;&amp;apos;;
    $part4 = &amp;apos;&amp;lt;/a&amp;gt;&amp;apos;;  

    $encoded = &amp;apos;&amp;lt;script type=&amp;quot;text/javascript&amp;quot;&amp;gt;&amp;apos;;
    $encoded .= &amp;quot;document.write(&amp;apos;$part1&amp;apos;);&amp;quot;;
    $encoded .= &amp;quot;document.write(&amp;apos;$part2&amp;apos;);&amp;quot;;
    foreach($email as $e)
    {
            $encoded .= &amp;quot;document.write(&amp;apos;$e&amp;apos;);&amp;quot;;
    }
    $encoded .= &amp;quot;document.write(&amp;apos;$part3&amp;apos;);&amp;quot;;
    foreach($linkText as $l)
    {
            $encoded .= &amp;quot;document.write(&amp;apos;$l&amp;apos;);&amp;quot;;
    }
    $encoded .= &amp;quot;document.write(&amp;apos;$part4&amp;apos;);&amp;quot;;
    $encoded .= &amp;apos;&amp;lt;/script&amp;gt;&amp;apos;;  

    return $encoded;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;4-PHP验证邮件地址&#34;&gt;&lt;a href=&#34;#4-PHP验证邮件地址&#34; class=&#34;headerlink&#34; title=&#34;4. PHP验证邮件地址&#34;&gt;&lt;/a&gt;4. PHP验证邮件地址&lt;/h3&gt;&lt;p&gt;电子邮件验证也许是中最常用的网页表单验证，此代码除了验证电子邮件地址，也可以选择检查邮件域所属 DNS 中的 MX 记录，使邮件验证功能更加强大。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function is_valid_email($email, $test_mx = false)
{
    if(eregi(&amp;quot;^([_a-z0-9-]+)(\.[_a-z0-9-]+)*@([a-z0-9-]+)(\.[a-z0-9-]+)*(\.[a-z]{2,4})$&amp;quot;, $email))
        if($test_mx)
        {
            list($username, $domain) = split(&amp;quot;@&amp;quot;, $email);
            return getmxrr($domain, $mxrecords);
        }
        else
            return true;
    else
        return false;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;5-PHP列出目录内容&#34;&gt;&lt;a href=&#34;#5-PHP列出目录内容&#34; class=&#34;headerlink&#34; title=&#34;5. PHP列出目录内容&#34;&gt;&lt;/a&gt;5. PHP列出目录内容&lt;/h3&gt;&lt;pre&gt;&lt;code&gt;function list_files($dir)
{
    if(is_dir($dir))
    {
        if($handle = opendir($dir))
        {
            while(($file = readdir($handle)) !== false)
            {
                if($file != &amp;quot;.&amp;quot; &amp;amp;&amp;amp; $file != &amp;quot;..&amp;quot; &amp;amp;&amp;amp; $file != &amp;quot;Thumbs.db&amp;quot;)
                {
                    echo &amp;apos;&amp;lt;a target=&amp;quot;_blank&amp;quot; href=&amp;quot;&amp;apos;.$dir.$file.&amp;apos;&amp;quot;&amp;gt;&amp;apos;.$file.&amp;apos;&amp;lt;/a&amp;gt;&amp;lt;br&amp;gt;&amp;apos;.&amp;quot;\n&amp;quot;;
                }
            }
            closedir($handle);
        }
    }
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;6-PHP销毁目录&#34;&gt;&lt;a href=&#34;#6-PHP销毁目录&#34; class=&#34;headerlink&#34; title=&#34;6. PHP销毁目录&#34;&gt;&lt;/a&gt;6. PHP销毁目录&lt;/h3&gt;&lt;p&gt;删除一个目录，包括它的内容。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/*****
*@dir - Directory to destroy
*@virtual[optional]- whether a virtual directory
*/
function destroyDir($dir, $virtual = false)
{
    $ds = DIRECTORY_SEPARATOR;
    $dir = $virtual ? realpath($dir) : $dir;
    $dir = substr($dir, -1) == $ds ? substr($dir, 0, -1) : $dir;
    if (is_dir($dir) &amp;amp;&amp;amp; $handle = opendir($dir))
    {
        while ($file = readdir($handle))
        {
            if ($file == &amp;apos;.&amp;apos; || $file == &amp;apos;..&amp;apos;)
            {
                continue;
            }
            elseif (is_dir($dir.$ds.$file))
            {
                destroyDir($dir.$ds.$file);
            }
            else
            {
                unlink($dir.$ds.$file);
            }
        }
        closedir($handle);
        rmdir($dir);
        return true;
    }
    else
    {
        return false;
    }
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;7-PHP解析-JSON-数据&#34;&gt;&lt;a href=&#34;#7-PHP解析-JSON-数据&#34; class=&#34;headerlink&#34; title=&#34;7. PHP解析 JSON 数据&#34;&gt;&lt;/a&gt;7. PHP解析 JSON 数据&lt;/h3&gt;&lt;p&gt;与大多数流行的 Web 服务如 Twitter 通过开放 API 来提供数据一样，它总是能够知道如何解析 API 数据的各种传送格式，包括 JSON，XML 等等。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;$json_string=&amp;apos;{&amp;quot;id&amp;quot;:1,&amp;quot;name&amp;quot;:&amp;quot;foo&amp;quot;,&amp;quot;email&amp;quot;:&amp;quot;foo@foobar.com&amp;quot;,&amp;quot;interest&amp;quot;:[&amp;quot;wordpress&amp;quot;,&amp;quot;php&amp;quot;]} &amp;apos;;
$obj=json_decode($json_string);
echo $obj-&amp;gt;name; //prints foo
echo $obj-&amp;gt;interest[1]; //prints php&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;8-PHP解析-XML-数据&#34;&gt;&lt;a href=&#34;#8-PHP解析-XML-数据&#34; class=&#34;headerlink&#34; title=&#34;8. PHP解析 XML 数据&#34;&gt;&lt;/a&gt;8. PHP解析 XML 数据&lt;/h3&gt;&lt;pre&gt;&lt;code&gt;//xml string
$xml_string=&amp;quot;&amp;lt;?xml version=&amp;apos;1.0&amp;apos;?&amp;gt;
&amp;lt;users&amp;gt;
   &amp;lt;user id=&amp;apos;398&amp;apos;&amp;gt;
      &amp;lt;name&amp;gt;Foo&amp;lt;/name&amp;gt;
      &amp;lt;email&amp;gt;foo@bar.com&amp;lt;/name&amp;gt;
   &amp;lt;/user&amp;gt;
   &amp;lt;user id=&amp;apos;867&amp;apos;&amp;gt;
      &amp;lt;name&amp;gt;Foobar&amp;lt;/name&amp;gt;
      &amp;lt;email&amp;gt;foobar@foo.com&amp;lt;/name&amp;gt;
   &amp;lt;/user&amp;gt;
&amp;lt;/users&amp;gt;&amp;quot;;  

//load the xml string using simplexml
$xml = simplexml_load_string($xml_string);  

//loop through the each node of user
foreach ($xml-&amp;gt;user as $user)
{
   //access attribute
   echo $user[&amp;apos;id&amp;apos;], &amp;apos;  &amp;apos;;
   //subnodes are accessed by -&amp;gt; operator
   echo $user-&amp;gt;name, &amp;apos;  &amp;apos;;
   echo $user-&amp;gt;email, &amp;apos;&amp;lt;br /&amp;gt;&amp;apos;;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;9-PHP创建日志缩略名&#34;&gt;&lt;a href=&#34;#9-PHP创建日志缩略名&#34; class=&#34;headerlink&#34; title=&#34;9. PHP创建日志缩略名&#34;&gt;&lt;/a&gt;9. PHP创建日志缩略名&lt;/h3&gt;&lt;p&gt;创建用户友好的日志缩略名。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function create_slug($string){
    $slug=preg_replace(&amp;apos;/[^A-Za-z0-9-]+/&amp;apos;, &amp;apos;-&amp;apos;, $string);
    return $slug;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;10-PHP获取客户端真实-IP-地址&#34;&gt;&lt;a href=&#34;#10-PHP获取客户端真实-IP-地址&#34; class=&#34;headerlink&#34; title=&#34;10. PHP获取客户端真实 IP 地址&#34;&gt;&lt;/a&gt;10. PHP获取客户端真实 IP 地址&lt;/h3&gt;&lt;p&gt;该函数将获取用户的真实 IP 地址，即便他使用代理服务器。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function getRealIpAddr()
{
    if (!emptyempty($_SERVER[&amp;apos;HTTP_CLIENT_IP&amp;apos;]))
    {
        $ip=$_SERVER[&amp;apos;HTTP_CLIENT_IP&amp;apos;];
    }
    elseif (!emptyempty($_SERVER[&amp;apos;HTTP_X_FORWARDED_FOR&amp;apos;]))
    //to check ip is pass from proxy
    {
        $ip=$_SERVER[&amp;apos;HTTP_X_FORWARDED_FOR&amp;apos;];
    }
    else
    {
        $ip=$_SERVER[&amp;apos;REMOTE_ADDR&amp;apos;];
    }
    return $ip;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;11-PHP强制性文件下载&#34;&gt;&lt;a href=&#34;#11-PHP强制性文件下载&#34; class=&#34;headerlink&#34; title=&#34;11. PHP强制性文件下载&#34;&gt;&lt;/a&gt;11. PHP强制性文件下载&lt;/h3&gt;&lt;p&gt;为用户提供强制性的文件下载功能。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/********************
*@file - path to file
*/
function force_download($file)
{
    if ((isset($file))&amp;amp;&amp;amp;(file_exists($file))) {
       header(&amp;quot;Content-length: &amp;quot;.filesize($file));
       header(&amp;apos;Content-Type: application/octet-stream&amp;apos;);
       header(&amp;apos;Content-Disposition: attachment; filename=&amp;quot;&amp;apos; . $file . &amp;apos;&amp;quot;&amp;apos;);
       readfile(&amp;quot;$file&amp;quot;);
    } else {
       echo &amp;quot;No file selected&amp;quot;;
    }
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;12-PHP创建标签云&#34;&gt;&lt;a href=&#34;#12-PHP创建标签云&#34; class=&#34;headerlink&#34; title=&#34;12. PHP创建标签云&#34;&gt;&lt;/a&gt;12. PHP创建标签云&lt;/h3&gt;&lt;pre&gt;&lt;code&gt;function getCloud( $data = array(), $minFontSize = 12, $maxFontSize = 30 )
{
    $minimumCount = min( array_values( $data ) );
    $maximumCount = max( array_values( $data ) );
    $spread       = $maximumCount - $minimumCount;
    $cloudHTML    = &amp;apos;&amp;apos;;
    $cloudTags    = array();  

    $spread == 0 &amp;amp;&amp;amp; $spread = 1;  

    foreach( $data as $tag =&amp;gt; $count )
    {
        $size = $minFontSize + ( $count - $minimumCount )
            * ( $maxFontSize - $minFontSize ) / $spread;
        $cloudTags[] = &amp;apos;&amp;lt;a style=&amp;quot;font-size: &amp;apos; . floor( $size ) . &amp;apos;px&amp;apos;
        . &amp;apos;&amp;quot; href=&amp;quot;#&amp;quot; title=&amp;quot;\&amp;apos;&amp;apos; . $tag  .
        &amp;apos;\&amp;apos; returned a count of &amp;apos; . $count . &amp;apos;&amp;quot;&amp;gt;&amp;apos;
        . htmlspecialchars( stripslashes( $tag ) ) . &amp;apos;&amp;lt;/a&amp;gt;&amp;apos;;
    }  

    return join( &amp;quot;\n&amp;quot;, $cloudTags ) . &amp;quot;\n&amp;quot;;
}
/**************************
****   Sample usage    ***/
$arr = Array(&amp;apos;Actionscript&amp;apos; =&amp;gt; 35, &amp;apos;Adobe&amp;apos; =&amp;gt; 22, &amp;apos;Array&amp;apos; =&amp;gt; 44, &amp;apos;Background&amp;apos; =&amp;gt; 43,
    &amp;apos;Blur&amp;apos; =&amp;gt; 18, &amp;apos;Canvas&amp;apos; =&amp;gt; 33, &amp;apos;Class&amp;apos; =&amp;gt; 15, &amp;apos;Color Palette&amp;apos; =&amp;gt; 11, &amp;apos;Crop&amp;apos; =&amp;gt; 42,
    &amp;apos;Delimiter&amp;apos; =&amp;gt; 13, &amp;apos;Depth&amp;apos; =&amp;gt; 34, &amp;apos;Design&amp;apos; =&amp;gt; 8, &amp;apos;Encode&amp;apos; =&amp;gt; 12, &amp;apos;Encryption&amp;apos; =&amp;gt; 30,
    &amp;apos;Extract&amp;apos; =&amp;gt; 28, &amp;apos;Filters&amp;apos; =&amp;gt; 42);
echo getCloud($arr, 12, 36);&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;13-PHP寻找两个字符串的相似性&#34;&gt;&lt;a href=&#34;#13-PHP寻找两个字符串的相似性&#34; class=&#34;headerlink&#34; title=&#34;13. PHP寻找两个字符串的相似性&#34;&gt;&lt;/a&gt;13. PHP寻找两个字符串的相似性&lt;/h3&gt;&lt;p&gt;PHP 提供了一个极少使用的 similar_text 函数，但此函数非常有用，用于比较两个字符串并返回相似程度的百分比。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;similar_text($string1, $string2, $percent);
//$percent will have the percentage of similarity&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;14-PHP在应用程序中使用-Gravatar-通用头像&#34;&gt;&lt;a href=&#34;#14-PHP在应用程序中使用-Gravatar-通用头像&#34; class=&#34;headerlink&#34; title=&#34;14. PHP在应用程序中使用 Gravatar 通用头像&#34;&gt;&lt;/a&gt;14. PHP在应用程序中使用 Gravatar 通用头像&lt;/h3&gt;&lt;p&gt;随着 WordPress 越来越普及，Gravatar 也随之流行。由于 Gravatar 提供了易于使用的 API，将其纳入应用程序也变得十分方便。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/******************
*@email - Email address to show gravatar for
*@size - size of gravatar
*@default - URL of default gravatar to use
*@rating - rating of Gravatar(G, PG, R, X)
*/
function show_gravatar($email, $size, $default, $rating)
{
    echo &amp;apos;&amp;lt;img src=&amp;quot;http://www.gravatar.com/avatar.php?gravatar_id=&amp;apos;.md5($email).
        &amp;apos;&amp;amp;default=&amp;apos;.$default.&amp;apos;&amp;amp;size=&amp;apos;.$size.&amp;apos;&amp;amp;rating=&amp;apos;.$rating.&amp;apos;&amp;quot; width=&amp;quot;&amp;apos;.$size.&amp;apos;px&amp;quot;
        height=&amp;quot;&amp;apos;.$size.&amp;apos;px&amp;quot; /&amp;gt;&amp;apos;;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;15-PHP在字符断点处截断文字&#34;&gt;&lt;a href=&#34;#15-PHP在字符断点处截断文字&#34; class=&#34;headerlink&#34; title=&#34;15. PHP在字符断点处截断文字&#34;&gt;&lt;/a&gt;15. PHP在字符断点处截断文字&lt;/h3&gt;&lt;p&gt;所谓断字 (word break)，即一个单词可在转行时断开的地方。这一函数将在断字处截断字符串。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;// Original PHP code by Chirp Internet: www.chirp.com.au
// Please acknowledge use of this code by including this header.
function myTruncate($string, $limit, $break=&amp;quot;.&amp;quot;, $pad=&amp;quot;...&amp;quot;) {
    // return with no change if string is shorter than $limit
    if(strlen($string) &amp;lt;= $limit)
        return $string;   

    // is $break present between $limit and the end of the string?
    if(false !== ($breakpoint = strpos($string, $break, $limit))) {
        if($breakpoint &amp;lt; strlen($string) - 1) {
            $string = substr($string, 0, $breakpoint) . $pad;
        }
    }
    return $string;
}
/***** Example ****/
$short_string=myTruncate($long_string, 100, &amp;apos; &amp;apos;);&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;16-PHP文件-Zip-压缩&#34;&gt;&lt;a href=&#34;#16-PHP文件-Zip-压缩&#34; class=&#34;headerlink&#34; title=&#34;16. PHP文件 Zip 压缩&#34;&gt;&lt;/a&gt;16. PHP文件 Zip 压缩&lt;/h3&gt;&lt;pre&gt;&lt;code&gt;/* creates a compressed zip file */
function create_zip($files = array(),$destination = &amp;apos;&amp;apos;,$overwrite = false) {
    //if the zip file already exists and overwrite is false, return false
    if(file_exists($destination) &amp;amp;&amp;amp; !$overwrite) { return false; }
    //vars
    $valid_files = array();
    //if files were passed in...
    if(is_array($files)) {
        //cycle through each file
        foreach($files as $file) {
            //make sure the file exists
            if(file_exists($file)) {
                $valid_files[] = $file;
            }
        }
    }
    //if we have good files...
    if(count($valid_files)) {
        //create the archive
        $zip = new ZipArchive();
        if($zip-&amp;gt;open($destination,$overwrite ? ZIPARCHIVE::OVERWRITE : ZIPARCHIVE::CREATE) !== true) {
            return false;
        }
        //add the files
        foreach($valid_files as $file) {
            $zip-&amp;gt;addFile($file,$file);
        }
        //debug
        //echo &amp;apos;The zip archive contains &amp;apos;,$zip-&amp;gt;numFiles,&amp;apos; files with a status of &amp;apos;,$zip-&amp;gt;status;  

        //close the zip -- done!
        $zip-&amp;gt;close();  

        //check to make sure the file exists
        return file_exists($destination);
    }
    else
    {
        return false;
    }
}
/***** Example Usage ***/
$files=array(&amp;apos;file1.jpg&amp;apos;, &amp;apos;file2.jpg&amp;apos;, &amp;apos;file3.gif&amp;apos;);
create_zip($files, &amp;apos;myzipfile.zip&amp;apos;, true);&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;17-PHP解压缩-Zip-文件&#34;&gt;&lt;a href=&#34;#17-PHP解压缩-Zip-文件&#34; class=&#34;headerlink&#34; title=&#34;17. PHP解压缩 Zip 文件&#34;&gt;&lt;/a&gt;17. PHP解压缩 Zip 文件&lt;/h3&gt;&lt;pre&gt;&lt;code&gt;/**********************
*@file - path to zip file
*@destination - destination directory for unzipped files
*/
function unzip_file($file, $destination){
    // create object
    $zip = new ZipArchive() ;
    // open archive
    if ($zip-&amp;gt;open($file) !== TRUE) {
        die (’Could not open archive’);
    }
    // extract contents to destination directory
    $zip-&amp;gt;extractTo($destination);
    // close archive
    $zip-&amp;gt;close();
    echo &amp;apos;Archive extracted to directory&amp;apos;;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;18-PHP为-URL-地址预设-http-字符串&#34;&gt;&lt;a href=&#34;#18-PHP为-URL-地址预设-http-字符串&#34; class=&#34;headerlink&#34; title=&#34;18. PHP为 URL 地址预设 http 字符串&#34;&gt;&lt;/a&gt;18. PHP为 URL 地址预设 http 字符串&lt;/h3&gt;&lt;p&gt;有时需要接受一些表单中的网址输入，但用户很少添加 http:// 字段，此代码将为网址添加该字段。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if (!preg_match(&amp;quot;/^(http|ftp):/&amp;quot;, $_POST[&amp;apos;url&amp;apos;])) {
   $_POST[&amp;apos;url&amp;apos;] = &amp;apos;http://&amp;apos;.$_POST[&amp;apos;url&amp;apos;];
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;19-PHP将网址字符串转换成超级链接&#34;&gt;&lt;a href=&#34;#19-PHP将网址字符串转换成超级链接&#34; class=&#34;headerlink&#34; title=&#34;19. PHP将网址字符串转换成超级链接&#34;&gt;&lt;/a&gt;19. PHP将网址字符串转换成超级链接&lt;/h3&gt;&lt;p&gt;该函数将 URL 和 E-mail 地址字符串转换为可点击的超级链接。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function makeClickableLinks($text) {
 $text = eregi_replace(&amp;apos;(((f|ht){1}tp://)[-a-zA-Z0-9@:%_+.~#?&amp;amp;//=]+)&amp;apos;,
 &amp;apos;&amp;lt;a href=&amp;quot;\1&amp;quot;&amp;gt;\1&amp;lt;/a&amp;gt;&amp;apos;, $text);
 $text = eregi_replace(&amp;apos;([[:space:]()[{}])(www.[-a-zA-Z0-9@:%_+.~#?&amp;amp;//=]+)&amp;apos;,
 &amp;apos;\1&amp;lt;a href=&amp;quot;http://\2&amp;quot;&amp;gt;\2&amp;lt;/a&amp;gt;&amp;apos;, $text);
 $text = eregi_replace(&amp;apos;([_.0-9a-z-]+@([0-9a-z][0-9a-z-]+.)+[a-z]{2,3})&amp;apos;,
 &amp;apos;&amp;lt;a href=&amp;quot;mailto:\1&amp;quot;&amp;gt;\1&amp;lt;/a&amp;gt;&amp;apos;, $text);  

return $text;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;20-PHP调整图像尺寸&#34;&gt;&lt;a href=&#34;#20-PHP调整图像尺寸&#34; class=&#34;headerlink&#34; title=&#34;20. PHP调整图像尺寸&#34;&gt;&lt;/a&gt;20. PHP调整图像尺寸&lt;/h3&gt;&lt;p&gt;创建图像缩略图需要许多时间，此代码将有助于了解缩略图的逻辑。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;/**********************
*@filename - path to the image
*@tmpname - temporary path to thumbnail
*@xmax - max width
*@ymax - max height
*/
function resize_image($filename, $tmpname, $xmax, $ymax)
{
    $ext = explode(&amp;quot;.&amp;quot;, $filename);
    $ext = $ext[count($ext)-1];  

    if($ext == &amp;quot;jpg&amp;quot; || $ext == &amp;quot;jpeg&amp;quot;)
        $im = imagecreatefromjpeg($tmpname);
    elseif($ext == &amp;quot;png&amp;quot;)
        $im = imagecreatefrompng($tmpname);
    elseif($ext == &amp;quot;gif&amp;quot;)
        $im = imagecreatefromgif($tmpname);  

    $x = imagesx($im);
    $y = imagesy($im);  

    if($x &amp;lt;= $xmax &amp;amp;&amp;amp; $y &amp;lt;= $ymax)
        return $im;  

    if($x &amp;gt;= $y) {
        $newx = $xmax;
        $newy = $newx * $y / $x;
    }
    else {
        $newy = $ymax;
        $newx = $x / $y * $newy;
    }  

    $im2 = imagecreatetruecolor($newx, $newy);
    imagecopyresized($im2, $im, 0, 0, 0, 0, floor($newx), floor($newy), $x, $y);
    return $im2;
}&lt;/code&gt;&lt;/pre&gt;&lt;h3 id=&#34;21-PHP检测-Ajax-请求&#34;&gt;&lt;a href=&#34;#21-PHP检测-Ajax-请求&#34; class=&#34;headerlink&#34; title=&#34;21. PHP检测 Ajax 请求&#34;&gt;&lt;/a&gt;21. PHP检测 Ajax 请求&lt;/h3&gt;&lt;p&gt;大多数的 JavaScript 框架如 jQuery，Mootools 等，在发出 Ajax 请求时，都会发送额外的 HTTP_X_REQUESTED_WITH 头部信息，头当他们一个ajax请求，因此你可以在服务器端侦测到 Ajax 请求。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if(!emptyempty($_SERVER[&amp;apos;HTTP_X_REQUESTED_WITH&amp;apos;]) &amp;amp;&amp;amp; strtolower($_SERVER[&amp;apos;HTTP_X_REQUESTED_WITH&amp;apos;]) == &amp;apos;xmlhttprequest&amp;apos;){
    //If AJAX Request Then
}else{
//something else
}&lt;/code&gt;&lt;/pre&gt;
